import { AuthError, FetchError } from "./errors";
import type { ManagementApiClientConfig, Tokens } from "./index";

// JWT utilities

function decodeJwtPayload(token: string): Record<string, unknown> {
  const parts = token.split(".");
  const payload = parts[1];
  if (parts.length !== 3 || payload === undefined) {
    throw new Error("Invalid JWT format");
  }
  // Base64url decode: replace URL-safe chars and add padding
  const base64 = payload.replace(/-/g, "+").replace(/_/g, "/");
  const padded = base64 + "=".repeat((4 - (base64.length % 4)) % 4);
  const decoded = atob(padded);
  return JSON.parse(decoded) as Record<string, unknown>;
}

export function extractWorkspaceId(accessToken: string): string {
  const payload = decodeJwtPayload(accessToken);
  const workspaceId = payload["workspace_id"];
  if (typeof workspaceId !== "string") {
    throw new Error("workspace_id not found in access token");
  }
  return workspaceId;
}

// PKCE utilities

function base64urlEncode(buffer: Uint8Array): string {
  const bytes = Array.from(buffer);
  const base64 = btoa(String.fromCharCode(...bytes));
  return base64.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

export function generateRandomString(length: number): string {
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return base64urlEncode(array);
}

export async function generateCodeChallenge(verifier: string): Promise<string> {
  const encoder = new TextEncoder();
  const data = encoder.encode(verifier);
  const hash = await crypto.subtle.digest("SHA-256", data);
  return base64urlEncode(new Uint8Array(hash));
}

// Token exchange utilities

export function tokenUrl(
  config: Required<Pick<ManagementApiClientConfig, "authBaseUrl">>,
): string {
  return `${config.authBaseUrl}/token`;
}

export type TokenResponse =
  | { status: "success"; accessToken: string; refreshToken: string }
  | { status: "error"; error: string; refreshTokenInvalid: boolean };

function formatOAuthError(data: unknown): string {
  if (typeof data === "object" && data !== null) {
    const errorData = data as Record<string, unknown>;
    const error = errorData["error"];
    const description = errorData["error_description"];
    if (typeof error === "string") {
      return typeof description === "string"
        ? `${error}: ${description}`
        : error;
    }
  }
  return "Unknown error";
}

export async function parseTokenResponse(
  response: Response,
): Promise<TokenResponse> {
  let data: unknown;
  try {
    data = await response.json();
  } catch {
    return {
      status: "error",
      error: `Failed to parse token response (status ${response.status})`,
      refreshTokenInvalid: false,
    };
  }

  if (response.status >= 400 && response.status < 500) {
    const errorMessage = formatOAuthError(data);
    // invalid_grant typically means the refresh token is expired or revoked
    const isInvalidGrant =
      typeof data === "object" &&
      data !== null &&
      (data as Record<string, unknown>)["error"] === "invalid_grant";
    return {
      status: "error",
      error: errorMessage,
      refreshTokenInvalid: isInvalidGrant,
    };
  }

  if (response.status !== 200) {
    return {
      status: "error",
      error: `Token request failed with status ${response.status}`,
      refreshTokenInvalid: false,
    };
  }

  if (
    typeof data !== "object" ||
    !data ||
    typeof (data as Record<string, unknown>)["access_token"] !== "string" ||
    typeof (data as Record<string, unknown>)["refresh_token"] !== "string"
  ) {
    return {
      status: "error",
      error: "Invalid token response format",
      refreshTokenInvalid: false,
    };
  }

  const tokenData = data as { access_token: string; refresh_token: string };
  return {
    status: "success",
    accessToken: tokenData.access_token,
    refreshToken: tokenData.refresh_token,
  };
}

export async function refreshAccessToken(
  config: Required<Pick<ManagementApiClientConfig, "clientId" | "authBaseUrl">>,
  refreshToken: string,
): Promise<TokenResponse> {
  const body = new URLSearchParams({
    grant_type: "refresh_token",
    refresh_token: refreshToken,
    client_id: config.clientId,
  });

  let response: Response;
  try {
    response = await fetch(tokenUrl(config), {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body,
    });
  } catch {
    return {
      status: "error",
      error: "Network error during token refresh",
      refreshTokenInvalid: false,
    };
  }

  return parseTokenResponse(response);
}

function tokensEqual(a: Tokens | null, b: Tokens | null): boolean {
  return (
    a?.workspaceId === b?.workspaceId &&
    a?.accessToken === b?.accessToken &&
    a?.refreshToken === b?.refreshToken
  );
}

export function createTokenRefreshingFetch(
  config: Required<ManagementApiClientConfig>,
) {
  let refreshPromise: Promise<Tokens> | null = null;

  const doRefresh = async (tokensThatFailed: Tokens): Promise<Tokens> => {
    const withRefreshLock =
      config.tokenStorage.withRefreshLock?.bind(config.tokenStorage) ??
      (<T>(fn: () => Promise<T>) => fn());

    return withRefreshLock(async () => {
      const currentTokens = await config.tokenStorage.getTokens();
      if (!currentTokens) {
        throw new AuthError("No tokens available. Please log in first.");
      }

      if (!tokensEqual(currentTokens, tokensThatFailed)) {
        return currentTokens;
      }

      if (!currentTokens.refreshToken) {
        throw new AuthError("No refresh token available. Please log in again.");
      }

      const result = await refreshAccessToken(
        config,
        currentTokens.refreshToken,
      );

      if (result.status === "error") {
        if (result.refreshTokenInvalid) {
          if (config.tokenStorage.clearTokensIfCurrent) {
            await config.tokenStorage.clearTokensIfCurrent(currentTokens);
          } else {
            await config.tokenStorage.clearTokens();
          }
        }
        throw new AuthError(result.error, result.refreshTokenInvalid);
      }

      const newTokens: Tokens = {
        accessToken: result.accessToken,
        refreshToken: result.refreshToken,
        workspaceId: extractWorkspaceId(result.accessToken),
      };
      await config.tokenStorage.setTokens(newTokens);

      return newTokens;
    });
  };

  const refreshTokens = async (tokensThatFailed: Tokens): Promise<Tokens> => {
    if (refreshPromise) {
      return refreshPromise;
    }

    refreshPromise = doRefresh(tokensThatFailed).finally(() => {
      refreshPromise = null;
    });

    return refreshPromise;
  };

  return async function tokenRefreshingFetch(
    request: globalThis.Request,
  ): Promise<Response> {
    request.signal.throwIfAborted();

    const tokens = await config.tokenStorage.getTokens();
    if (!tokens) {
      throw new AuthError("No tokens available. Please log in first.");
    }

    const requestCloneForRetry = request.clone();
    request.headers.set("Authorization", `Bearer ${tokens.accessToken}`);

    let response: Response;
    try {
      response = await fetch(request);
    } catch (error) {
      request.signal.throwIfAborted();
      throw new FetchError("Network request failed", error);
    }

    if (response.status === 401) {
      request.signal.throwIfAborted();

      const newTokens = await refreshTokens(tokens);
      requestCloneForRetry.headers.set(
        "Authorization",
        `Bearer ${newTokens.accessToken}`,
      );
      try {
        response = await fetch(requestCloneForRetry);
      } catch (error) {
        request.signal.throwIfAborted();
        throw new FetchError(
          "Network request failed after token refresh",
          error,
        );
      }
    }

    return response;
  };
}
